form:Form.form:Scripts:
		function selaux()
	{
				Ctrl('datosFijos').SetCValue(1);
				Ctrl('datosAcumuladores').SetCValue(1);
				Ctrl('datosParametros').SetCValue(1);
				Ctrl('datosEmbargos').SetCValue(1);
				Ctrl('datosDeducciones').SetCValue(1);
				Ctrl('datosAnticipos').SetCValue(1);
				Ctrl('Datosrecibos').SetCValue(1);


	}

function sel4()		
		{
			if (Ctrl('datosFijos').GetCValue() =="0")
			{

				Ctrl('datosFijos').SetCValue(1);
				Ctrl('datosAcumuladores').SetCValue(1);
				Ctrl('datosParametros').SetCValue(1);
				Ctrl('datosEmbargos').SetCValue(1);
				Ctrl('datosDeducciones').SetCValue(1);
				Ctrl('datosAnticipos').SetCValue(1);  
				Ctrl('Datosrecibos').SetCValue(1);
			}else
			{				
				Ctrl('datosFijos').SetCValue(0);
				Ctrl('datosAcumuladores').SetCValue(0);
				Ctrl('datosParametros').SetCValue(0);
				Ctrl('datosEmbargos').SetCValue(0);
				Ctrl('datosDeducciones').SetCValue(0);
				Ctrl('datosAnticipos').SetCValue(0);
				Ctrl('Datosrecibos').SetCValue(0);
			}			
		}
